import argparse
import json
import os
import numpy as np
import heapq

from cogniplan_env import ExplorationEnv


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n['coords'])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get('coords', nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n['coords'], dtype=float) -
                    np.array(nodes[j]['coords'], dtype=float)
                ))
                if w > 0:
                    adj[i].append((j, w))
    r_idx = N
    adj.append([])
    node_to_nb = {}
    for idx, nb in enumerate(neighbors):
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) - np.array(nb, dtype=float)
        ))
        if w > 0:
            adj[r_idx].append((j, w))
            adj[j].append((r_idx, w))
            node_to_nb[j] = idx
    return adj, coord_to_idx, r_idx, node_to_nb


def first_step_index(prev, r_idx, target_j, node_to_nb):
    if prev[target_j] is None:
        return None
    cur = target_j
    depth = 0
    max_depth = len(prev) + 5
    while prev[cur] != r_idx and prev[cur] is not None and depth < max_depth:
        cur = prev[cur]
        depth += 1
    if prev[cur] == r_idx and cur in node_to_nb:
        return node_to_nb[cur]
    return None


class GreedyPlanner:
    def __init__(self, dist_denom=2.0, reverse_penalty=0.3, visited_penalty=0.1, persist_boost=1.05):
        self.dist_denom = float(dist_denom)
        self.reverse_penalty = float(reverse_penalty)
        self.visited_penalty = float(visited_penalty)
        self.persist_boost = float(persist_boost)
        self.reset()

    def reset(self):
        self.prev_pos = None
        self.prev_target_coord = None
        self.step_count = 0

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs['robot_pos'], dtype=float)
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        frontiers = obs.get('frontiers', [])

        if not neighbors:
            self.prev_pos = robot_pos
            return None

        adj, coord_to_idx, r_idx, node_to_nb = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        prev_target_j = None
        if self.prev_target_coord is not None:
            prev_target_j = coord_to_idx.get(round_coord(self.prev_target_coord))

        candidate_js = [j for j in range(N) if j in node_to_nb and dist[j] < float('inf')]
        if not candidate_js:
            self.prev_pos = robot_pos
            return self._fallback(neighbors, frontiers, nodes, coord_to_idx, robot_pos)

        primary = [j for j in candidate_js if float(nodes[j].get('utility', 0.0)) > 0]
        if not primary:
            primary = candidate_js

        best_score = -float('inf')
        best_j = None
        for j in primary:
            utility = float(nodes[j].get('utility', 0.0))
            d = dist[j]
            score = utility / (d + self.dist_denom)

            if nodes[j].get('visited', False):
                score *= (1.0 - self.visited_penalty)

            if prev_target_j is not None and j == prev_target_j:
                score *= self.persist_boost

            fs = first_step_index(prev, r_idx, j, node_to_nb)
            if fs is not None and reverse_idx is not None and fs == reverse_idx:
                score *= (1.0 - self.reverse_penalty)

            if score > best_score:
                best_score = score
                best_j = j

        if best_j is None:
            target = self._fallback(neighbors, frontiers, nodes, coord_to_idx, robot_pos)
            self.prev_pos = robot_pos
            return target

        self.prev_target_coord = nodes[best_j]['coords']
        self.prev_pos = robot_pos
        return neighbors[node_to_nb[best_j]]

    def _fallback(self, neighbors, frontiers, nodes, coord_to_idx, robot_pos):
        if frontiers and neighbors:
            fr_arr = np.array(frontiers, dtype=float)
            best_idx = None
            best_d = float('inf')
            for idx, nb in enumerate(neighbors):
                dd = np.min(np.linalg.norm(fr_arr - np.array(nb, dtype=float), axis=1))
                if dd < best_d:
                    best_d = dd
                    best_idx = idx
            if best_idx is not None:
                return neighbors[best_idx]
        if neighbors:
            best_idx = None
            best_d = float('inf')
            for idx, nb in enumerate(neighbors):
                j = coord_to_idx.get(round_coord(nb))
                if j is not None and not nodes[j].get('visited', False):
                    d = float(np.linalg.norm(np.array(nb, dtype=float) - robot_pos))
                    if d < best_d:
                        best_d = d
                        best_idx = idx
            if best_idx is not None:
                return neighbors[best_idx]
        return neighbors[0] if neighbors else None


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get('done', False):
            break
    return env.get_metrics()


def evaluate_all(data_path, planner):
    eval_config_path = os.path.join(data_path, 'eval_config.json')
    maps_dir = os.path.join(data_path, 'maps_eval')
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, 'r') as f:
            eval_config = json.load(f)
        if 'episodes' in eval_config:
            episodes = eval_config['episodes']
        else:
            for env_type in eval_config.get('env_types', ['room', 'tunnel', 'outdoor']):
                subdir = os.path.join(maps_dir, env_type)
                if os.path.isdir(subdir):
                    for fname in sorted(os.listdir(subdir)):
                        if fname.endswith('.png'):
                            episodes.append({
                                'map_path': os.path.join('maps_eval', env_type, fname),
                                'env_type': env_type
                            })
    else:
        for env_type in ['room', 'tunnel', 'outdoor']:
            subdir = os.path.join(maps_dir, env_type)
            if os.path.isdir(subdir):
                for fname in sorted(os.listdir(subdir)):
                    if fname.endswith('.png'):
                        episodes.append({
                            'map_path': os.path.join('maps_eval', env_type, fname),
                            'env_type': env_type
                        })

    per_episode = []
    per_type = {}
    for ep in episodes:
        map_path = os.path.join(data_path, ep['map_path'])
        env_type = ep['env_type']
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get('success', False) else 0
        travel_distance = float(metrics.get('travel_distance', 0.0))
        explored_rate = float(metrics.get('explored_rate', 0.0))
        per_episode.append({
            'map_path': ep['map_path'],
            'env_type': env_type,
            'success': success,
            'travel_distance': travel_distance,
            'explored_rate': explored_rate
        })
        if env_type not in per_type:
            per_type[env_type] = {'successes': [], 'distances': [], 'explored': []}
        per_type[env_type]['successes'].append(success)
        per_type[env_type]['distances'].append(travel_distance)
        per_type[env_type]['explored'].append(explored_rate)

    total_episodes = len(per_episode)
    explored_rate = sum(e['explored_rate'] for e in per_episode) / total_episodes if total_episodes else 0.0
    successful_distances = [e['travel_distance'] for e in per_episode if e['success']]
    travel_distance = sum(successful_distances) / len(successful_distances) if successful_distances else 0.0
    success_rate = sum(e['success'] for e in per_episode) / total_episodes if total_episodes else 0.0

    per_type_out = {}
    for env_type, stats in per_type.items():
        s = stats['successes']
        d = [x for x, succ in zip(stats['distances'], s) if succ]
        e = stats['explored']
        per_type_out[env_type] = {
            'explored_rate': sum(e) / len(e) if e else 0.0,
            'travel_distance': sum(d) / len(d) if d else 0.0,
            'success_rate': sum(s) / len(s) if s else 0.0
        }

    return {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_episodes
    }


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    cfg_path = os.path.join(args.checkpoint, 'planner_cfg.json')
    cfg = {}
    if os.path.exists(cfg_path):
        with open(cfg_path, 'r') as f:
            cfg = json.load(f)

    planner = GreedyPlanner(**cfg)
    results = evaluate_all(args.data_path, planner)

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, 'w') as f:
        json.dump(results, f, indent=2)
    print(f"Wrote results to {args.output}")


if __name__ == '__main__':
    main()
